function buildPermissions(role) {
    const isAdmin = [
        "ADMIN",
        "SUPER_ADMIN"
    ].includes(role);
    const isManager = isAdmin || role === "MANAGER";
    const isApprover = role === "APPROVER";
    const isUser = role === "USER";
    return {
        admin: isAdmin,
        super_admin: role === "SUPER_ADMIN",
        create: isManager,
        templates: isAdmin,
        matrix: isAdmin,
        pending: isAdmin || isApprover,
        topDashboard: !isUser
    };
}
